from anthropic import Anthropic
import json

client = Anthropic()

def generate_funnel_executive_brief(
    organisation: str,
    period: str,
    current_funnel: dict,
    prior_funnel: dict,
    target_funnel: dict
) -> str:
    """Generate a one-page executive brief comparing funnel actuals vs targets."""
    def conv(a, b):
        return f"{a/max(b,1)*100:.1f}%" if b else "N/A"
    def delta(curr, prior):
        d = curr - prior
        return f"+{d}" if d >= 0 else str(d)

    prompt = f"""Write a one-page executive brief on Claude adoption funnel performance.

Organisation: {organisation}
Period: {period}

Funnel actuals vs targets vs prior period:
Stage       | Prior   | Current | Target  | vs Target | vs Prior
Aware       | {prior_funnel.get("aware",0):7} | {current_funnel.get("aware",0):7} | {target_funnel.get("aware",0):7} | {delta(current_funnel.get("aware",0), target_funnel.get("aware",0)):9} | {delta(current_funnel.get("aware",0), prior_funnel.get("aware",0))}
Activated   | {prior_funnel.get("activated",0):7} | {current_funnel.get("activated",0):7} | {target_funnel.get("activated",0):7} | {delta(current_funnel.get("activated",0), target_funnel.get("activated",0)):9} | {delta(current_funnel.get("activated",0), prior_funnel.get("activated",0))}
Regular     | {prior_funnel.get("regular",0):7} | {current_funnel.get("regular",0):7} | {target_funnel.get("regular",0):7} | {delta(current_funnel.get("regular",0), target_funnel.get("regular",0)):9} | {delta(current_funnel.get("regular",0), prior_funnel.get("regular",0))}
Embedded    | {prior_funnel.get("embedded",0):7} | {current_funnel.get("embedded",0):7} | {target_funnel.get("embedded",0):7} | {delta(current_funnel.get("embedded",0), target_funnel.get("embedded",0)):9} | {delta(current_funnel.get("embedded",0), prior_funnel.get("embedded",0))}
Advocate    | {prior_funnel.get("advocate",0):7} | {current_funnel.get("advocate",0):7} | {target_funnel.get("advocate",0):7} | {delta(current_funnel.get("advocate",0), target_funnel.get("advocate",0)):9} | {delta(current_funnel.get("advocate",0), prior_funnel.get("advocate",0))}

Write a 3-paragraph brief (200 words):
Para 1: Overall status and most important number
Para 2: Where the programme is ahead of target and why
Para 3: Where the programme is behind, the root cause, and one specific ask of the executive reader"""

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": prompt}]
    )
    return response.content[0].text

brief = generate_funnel_executive_brief(
    organisation="Apex Financial Services (2,400 employees)",
    period="Q2 2025",
    current_funnel={"aware": 1800, "activated": 920, "regular": 340, "embedded": 88, "advocate": 22},
    prior_funnel={"aware": 1400, "activated": 650, "regular": 210, "embedded": 52, "advocate": 11},
    target_funnel={"aware": 2000, "activated": 1000, "regular": 400, "embedded": 100, "advocate": 30}
)
print(brief)
